#include <vector>
#include <map>
#include <algorithm>

using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<long long> ans;

    // Preprocess the array to create a list of maps, where each map contains the counts of each number in the subarray starting at index i
    vector<map<long long, long long>> count_list;
    map<long long, long long> freq;
    for (int i = 0; i < n; i++) {
        freq[nums[i]]++;
        count_list.push_back(freq);
    }

