    for (const auto& query : queries) {
        int l = query[0];
        int r = query[1];
        int threshold = query[2];

        map<long long, long long> freq_dict = count_list[l];
        vector<pair<long long, long long>> candidates;

        // We need to consider only elements that appear at least threshold times in the subarray
        for (const auto& [key, val] : freq_dict) {
            if (val >= threshold) {
                candidates.emplace_back(key, val);
            }
        }

        // Sort candidates by frequency (descending), then by value (ascending)
        sort(candidates.begin(), candidates.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
            return a.second > b.second || (a.second == b.second && a.first < b.first);
        });

        if (!candidates.empty()) {
            ans.push_back(candidates[0].first);
        } else {
            ans.push_back(-1);
        }
    }

    return ans;
}
